// ═══ MINI COMPONENTS ═══════════════════════════════════════════════
function GaugeChart({ value, target=85, color, size=100 }) {
  const r=43,cx=size/2,cy=size/2,circ=2*Math.PI*r;
  const dash=v=>(Math.min(v,100)/100)*circ*0.75;
  const rot=-225;
  const col=value>=target?color:value>=target*0.85?"#f59e0b":"#ef4444";
  return (
    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
      <circle cx={cx} cy={cy} r={r} fill="none" stroke="#1e293b" strokeWidth="9" strokeDasharray={`${circ*0.75} ${circ*0.25}`} strokeLinecap="round" transform={`rotate(${rot} ${cx} ${cy})`}/>
      <circle cx={cx} cy={cy} r={r} fill="none" stroke={col} strokeWidth="9" strokeDasharray={`${dash(value)} ${circ-dash(value)}`} strokeLinecap="round" style={{transition:"stroke-dasharray 0.7s ease"}} transform={`rotate(${rot} ${cx} ${cy})`}/>
      <line x1={cx} y1={cy-r+14} x2={cx} y2={cy-r+4} stroke="#f59e0b70" strokeWidth="2" strokeLinecap="round" transform={`rotate(${rot+(target/100)*270} ${cx} ${cy})`}/>
      <text x={cx} y={cy+5} textAnchor="middle" fill="white" fontSize="17" fontWeight="700" fontFamily="'DM Mono',monospace">{value}%</text>
      <text x={cx} y={cy+17} textAnchor="middle" fill="#475569" fontSize="8" fontFamily="'DM Sans',sans-serif">TGT {target}%</text>
    </svg>
  );
}
function Spark({data,color="#22d3ee",h=34,w=100,target}){
  if(!data||data.length<2)return null;
  const mn=Math.min(...data)-1,mx=Math.max(...data,target||0)+1;
  const px=i=>(i/(data.length-1))*w, py=v=>h-((v-mn)/(mx-mn))*h;
  const pts=data.map((v,i)=>`${px(i)},${py(v)}`).join(" ");
  const ty=target?py(target):null;
  return(<svg width={w} height={h} viewBox={`0 0 ${w} ${h}`}>{target&&<line x1="0" x2={w} y1={ty} y2={ty} stroke="#f59e0b35" strokeWidth="1" strokeDasharray="2 2"/>}<polyline points={pts} fill="none" stroke={color} strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/><circle cx={px(data.length-1)} cy={py(data[data.length-1])} r="2.5" fill={color}/></svg>);
}
function StatusDot({status}){
  const c={running:"#22c55e",idle:"#f59e0b",breakdown:"#ef4444"}[status]||"#64748b";
  return<span style={{display:"inline-block",width:7,height:7,borderRadius:"50%",background:c,boxShadow:status==="running"?`0 0 5px ${c}`:"none",marginRight:5}}/>;
}
function MiniBar({pct,color}){
  return<div style={{background:"#0f172a",borderRadius:3,height:5,width:"100%",overflow:"hidden"}}><div style={{height:"100%",width:`${Math.min(pct,100)}%`,background:color,borderRadius:3,transition:"width 0.5s ease"}}/></div>;
}
function TrendSVG({data,metrics,h=105}){
  const w=400,pad={t:7,r:7,b:20,l:26};
  const iw=w-pad.l-pad.r,ih=h-pad.t-pad.b;
  const mn=55,mx=102;
  const xs=i=>pad.l+(i/(data.length-1))*iw;
  const ys=v=>pad.t+ih-((v-mn)/(mx-mn))*ih;
  return(<svg width="100%" viewBox={`0 0 ${w} ${h}`} style={{overflow:"visible"}}>
    {[60,70,80,90,100].map(v=><line key={v} x1={pad.l} x2={w-pad.r} y1={ys(v)} y2={ys(v)} stroke="#1e293b" strokeWidth="1" strokeDasharray="2 4"/>)}
    {[60,80,100].map(v=><text key={v} x={pad.l-3} y={ys(v)+3} textAnchor="end" fill="#334155" fontSize="7">{v}</text>)}
    {metrics.map(m=>{const pts=data.map((d,i)=>`${xs(i)},${ys(d[m.key])}`).join(" ");return<polyline key={m.key} points={pts} fill="none" stroke={m.color} strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"/>;})}
    {data.map((d,i)=><text key={i} x={xs(i)} y={h-3} textAnchor="middle" fill="#334155" fontSize="7">{d.label}</text>)}
  </svg>);
}
function OutputBar({data}){
  const mx=Math.max(...data.map(d=>Math.max(d.output,d.target)))+20;
  const w=400,h=82,bw=26,gap=11,pL=22,pB=17,pT=5;
  const ih=h-pT-pB,tot=data.length*(bw+gap),sx=pL+(w-pL-tot)/2;
  return(<svg width="100%" viewBox={`0 0 ${w} ${h}`}>{data.map((d,i)=>{const x=sx+i*(bw+gap),bh=(d.output/mx)*ih,th=(d.target/mx)*ih,col=d.output>=d.target?"#22c55e":"#ef4444";return(<g key={i}><rect x={x} y={h-pB-bh} width={bw} height={bh} rx="2" fill={col} opacity="0.85"/><line x1={x-2} x2={x+bw+2} y1={h-pB-th} y2={h-pB-th} stroke="#f59e0b" strokeWidth="1.5" strokeDasharray="3 2"/><text x={x+bw/2} y={h-2} textAnchor="middle" fill="#334155" fontSize="7">{d.hour}</text><text x={x+bw/2} y={h-pB-bh-2} textAnchor="middle" fill={col} fontSize="7">{d.output}</text></g>);})}
  </svg>);
}
function HeatMap({data,days,shifts}){
  const gc=v=>v>=85?"#166534":v>=75?"#15803d":v>=65?"#ca8a04":"#dc2626";
  return(<div>
    <div style={{display:"grid",gridTemplateColumns:`54px repeat(${days.length},1fr)`,gap:2,marginBottom:3}}><div/>{days.map(d=><div key={d} style={{textAlign:"center",fontSize:9,color:"#475569"}}>{d}</div>)}</div>
    {shifts.map((s,si)=><div key={s} style={{display:"grid",gridTemplateColumns:`54px repeat(${days.length},1fr)`,gap:2,marginBottom:2}}><div style={{fontSize:9,color:"#475569",display:"flex",alignItems:"center"}}>{s}</div>{days.map((d,di)=><div key={d} style={{background:gc(data[si][di]),borderRadius:2,padding:"3px 1px",textAlign:"center",fontSize:8,color:"rgba(255,255,255,0.9)",fontFamily:"'DM Mono',monospace"}}>{data[si][di]}</div>)}</div>)}
    <div style={{display:"flex",gap:8,marginTop:5}}>{[["≥85","#166534"],["75-84","#15803d"],["65-74","#ca8a04"],["<65","#dc2626"]].map(([l,c])=><div key={l} style={{display:"flex",alignItems:"center",gap:3}}><div style={{width:9,height:9,borderRadius:1,background:c}}/><span style={{fontSize:8,color:"#64748b"}}>{l}%</span></div>)}</div>
  </div>);
}

